// src/Comments/CommentItem.js
export default function CommentItem({
                                        comment,
                                        user,
                                        isAdmin,
                                        toggleReaction,
                                        onReply,
                                        onDelete
                                    }) {
    const myReaction = comment.myReaction;
    const counts = comment.reactionCounts || {};

    return (
        <li className="comment-item">
            <div className="comment-body">
                <strong>{comment.username}</strong>
                <p>{comment.comment}</p>
            </div>

            <div className="comment-actions">
                {["LIKE", "FIRE", "LAUGH"].map(type => (
                    <button
                        key={type}
                        className={myReaction === type ? "active" : ""}
                        onClick={() => toggleReaction(comment, type)}
                    >
                        {type === "LIKE" && "👍"}
                        {type === "FIRE" && "🔥"}
                        {type === "LAUGH" && "😂"}
                        {counts[type] > 0 && ` ${counts[type]}`}
                    </button>
                ))}

                <button onClick={() => onReply(comment.id)}>Reply</button>

                {(isAdmin || user?.username === comment.username) && (
                    <button onClick={() => onDelete(comment.id)}>
                        Delete
                    </button>
                )}
            </div>
        </li>
    );
}
